SELECT CadastroAcolhidos.CódigoAcolhido, CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.DataNascimentoAcolhido, fncIdadeCompleta(Nz([DataNascimentoAcolhido],0)) AS [Idade Completa], CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.EntidadeAcolhimento, fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento], CadastroAcolhidos.MotivoAcolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.NGuiaAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.AcolhidoEvadido, CadastroAcolhidos.DataEvasão, CadastroAcolhidos.DataRetorno, CadastroAcolhidos.MotivoDesacolhimento, CadastroAcolhidos.AcolhidoDestituido, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.DataTransito, CadastroAcolhidos.AcolhidoAdotado, CadastroAcolhidos.DadosAdocao, CadastroAcolhidos.FaseProcessual, CadastroAcolhidos.ImpulsoProcessual, CadastroAcolhidos.Observações, CadastroAcolhidos.AtualizacaoFicha
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento) Is Null));
